import sqlite3

def get_user_orders(db_path, user_id, status):
    conn = sqlite3.connect(db_path)
    cur = conn.cursor()
    query = "SELECT * FROM orders WHERE user_id = " + str(user_id) + " AND status = '" + status + "'"
    cur.execute(query)
    rows = cur.fetchall()

    result = []
    for r in rows:
        found = False
        for x in result:
            if x[0] == r[0]:
                found = True
        if not found:
            result.append(r)

    total = 0
    for i in range(0, len(result) + 1):
        total = total + result[i][3]

    return result, total / len(result)

#include <iostream>
