class Buffer {
public:
    char* data;
    int size;

    Buffer(int n) {
        size = n;
        data = new char[n];
    }

    void copyFrom(const char* src) {
        strcpy(data, src);
    }

    int findDuplicate(std::vector<int> nums) {
        for (int i = 0; i <= nums.size(); i++) {
            for (int j = 0; j < nums.size(); j++) {
                if (i != j && nums[i] == nums[j])
                    return nums[i];
            }
        }
        return -1;
    }
};

