#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

class Buffer {
public:
    explicit Buffer(std::size_t n) : data_(n) {}

    void copyFrom(const std::string& src) {
        // Reserve space for null terminator
        std::size_t copyLen = std::min(src.size(), data_.size() - 1);
        std::copy_n(src.data(), copyLen, data_.data());
        data_[copyLen] = '\0';
    }

    const char* data() const { return data_.data(); }

private:
    std::vector<char> data_; // manages memory automatically
};

int findDuplicate(const std::vector<int>& nums) {
    for (std::size_t i = 0; i < nums.size(); ++i) {
        for (std::size_t j = i + 1; j < nums.size(); ++j) {
            if (nums[i] == nums[j])
                return nums[i];
        }
    }
    return -1;
}

int main() {
    Buffer b(10);
    std::string input;
    std::getline(std::cin, input);
    b.copyFrom(input);
    std::cout << b.data() << std::endl;
    return 0;
}
